object AwsCredentialManager {

  /**
   * Provides credentials using the default credential provider chain.
   * This chain automatically searches for credentials in a specific order:
   * 1. Environment variables (AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, AWS_SESSION_TOKEN)
   * 2. Java system properties (aws.accessKeyId, aws.secretKey, aws.sessionToken)
   * 3. Web Identity Token credentials from the environment or container
   * 4. Credential profiles file (~/.aws/credentials, or as specified by AWS_SHARED_CREDENTIALS_FILE)
   * 5. ECS container credentials (if running in ECS)
   * 6. EC2 instance metadata service (if running on an EC2 instance)
   *
   * This is generally the recommended approach for AWS SDK applications.
   */
  def defaultProvider: AWSCredentialsProvider = {
    println("Using DefaultAWSCredentialsProviderChain...")
    new DefaultAWSCredentialsProviderChain()
  }

  /**
   * Provides static credentials. This is generally NOT recommended for production environments
   * as it hardcodes sensitive information. Use it for local testing or very specific scenarios
   * where credentials are provided securely (e.g., from an encrypted configuration vault).
   *
   * @param accessKey Your AWS Access Key ID.
   * @param secretKey Your AWS Secret Access Key.
   */
  def staticProvider(accessKey: String, secretKey: String): AWSCredentialsProvider = {
    println("Using static credentials provider...")
    new AWSStaticCredentialsProvider(new BasicAWSCredentials(accessKey, secretKey))
  }

  /**
   * Provides credentials from a specific profile in the AWS shared credentials file
   * (typically located at `~/.aws/credentials` or specified by `AWS_SHARED_CREDENTIALS_FILE`).
   *
   * @param profileName The name of the profile to use (e.g., "default", "my-profile").
   */
  def profileProvider(profileName: String): AWSCredentialsProvider = {
    println(s"Using profile credentials provider for profile: '$profileName'...")
    new ProfileCredentialsProvider(profileName)
  }

  /**
   * Provides temporary session credentials, typically obtained from AWS Security Token Service (STS)
   * operations like `AssumeRole`, `GetFederationToken`, or `GetSessionToken`. These credentials
   * include an access key, a secret key, and a session token, and have a limited lifespan.
   *
   * @param accessKey Your AWS Access Key ID for the session.
   * @param secretKey Your AWS Secret Access Key for the session.
   * @param sessionToken Your AWS Session Token for the session.
   */
  def sessionProvider(accessKey: String, secretKey: String, sessionToken: String): AWSCredentialsProvider = {
    println("Using session credentials provider...")
    new AWSStaticCredentialsProvider(new BasicSessionCredentials(accessKey, secretKey, sessionToken))
  }
