S3Service.scala
import com.amazonaws.auth.AWSCredentialsProvider
import com.amazonaws.regions.Region
import com.amazonaws.services.s3.AmazonS3ClientBuilder
import com.amazonaws.services.s3.model.Bucket
import com.amazonaws.{AmazonClientException, AmazonServiceException}

import scala.jdk.CollectionConverters._

/**
 * A service class for interacting with AWS S3.
 *
 * @param credentialsProvider The AWS credentials provider to use for authentication.
 * @param region The AWS region where S3 operations will be performed.
 */
class S3Service(credentialsProvider: AWSCredentialsProvider, region: Region) {

  // Initialize the S3 client with the provided credentials and region
  private val s3Client = AmazonS3ClientBuilder.standard()
    .withCredentials(credentialsProvider)
    .withRegion(region.getName)
    .build()

  /**
   * Lists all S3 buckets accessible by the current credentials in the configured region.
   *
   * @return A List of S3 Bucket objects if successful, or an empty list if an error occurs.
   */
  def listS3Buckets(): List[Bucket] = {
    println(s"Attempting to list S3 buckets in region ${region.getName}...")
    try {
      val buckets = s3Client.listBuckets().asScala.toList
      println(s"Successfully listed ${buckets.size} buckets.")
      buckets.foreach(bucket => println(s"- ${bucket.getName} (Created: ${bucket.getCreationDate})"))
      buckets
    } catch {
      case ase: AmazonServiceException =>
        System.err.println("AmazonServiceException occurred during S3 operation:")
        System.err.println(s"Error Message: ${ase.getMessage}")
        System.err.println(s"HTTP Status Code: ${ase.getStatusCode}")
        System.err.println(s"AWS Error Code: ${ase.getErrorCode}")
        System.err.println(s"Error Type: ${ase.getErrorType}")
        System.err.println(s"Request ID: ${ase.getRequestId}")
        List.empty[Bucket]
      case ace: AmazonClientException =>
        System.err.println("AmazonClientException occurred during S3 operation:")
        System.err.println(s"Error Message: ${ace.getMessage}")
        List.empty[Bucket]
      case e: Exception =>
        System.err.println(s"An unexpected error occurred during S3 operation: ${e.getMessage}")
        List.empty[Bucket]
    }
  }

  /**
   * Shuts down the S3 client, releasing resources. It's good practice to call this
   * when the service is no longer needed.
   */
  def shutdown(): Unit = {
    s3Client.shutdown()
    println("S3 client shut down.")
  }
}

